<script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import PageHeader from'../../components/PageHeader.vue';import{medicalApi,type PaymentOrder}from'../../api/medical';import{currentPatient,setPatientBalance,refreshCurrentPatientBalance}from'../../stores/session';const tab=ref(0),bills=ref<PaymentOrder[]>([]),loading=ref(false);async function load(){const patient=currentPatient.value;if(!patient)return;loading.value=true;try{const status=tab.value===0?0:tab.value===1?1:null;const data=await medicalApi.paymentOrders(patient.patientId,status);bills.value=data.orders||[]}finally{loading.value=false}}async function changeTab(index:number){tab.value=index;await load()}async function pay(item:PaymentOrder){const confirmed=await new Promise<boolean>(resolve=>uni.showModal({title:'确认支付',content:`${item.departmentName||'门诊费用'} ¥${Number(item.pendingAmount||0).toFixed(2)}`,success:r=>resolve(r.confirm),fail:()=>resolve(false)}));if(!confirmed)return;const result=await medicalApi.payAll(item.registerId);if(typeof result.accountBalance==='number'&&currentPatient.value)setPatientBalance(currentPatient.value.patientId,result.accountBalance);else refreshCurrentPatientBalance();uni.showToast({title:'支付成功',icon:'success'});await load()}onShow(()=>{refreshCurrentPatientBalance();load()})</script>
<template><view class="page-shell"><PageHeader title="门诊缴费" subtitle="查看账单并完成费用支付"/><view class="balance"><text>账户余额</text><text>¥ {{Number(currentPatient?.accountBalance||0).toFixed(2)}}</text><text>余额可用于门诊费用支付</text></view><view class="tabs card"><text v-for="(item,index) in ['待缴费','已支付','全部']" :key="item" :class="{active:tab===index}" @tap="changeTab(index)">{{item}}</text></view><view v-if="loading" class="bill card">正在加载账单…</view><view v-for="item in bills" :key="item.registerId" class="bill card"><view class="bill-head"><text>{{item.departmentName||'门诊费用'}}</text><text :class="{paid:item.status===1}">{{item.statusName}}</text></view><text class="bill-desc">{{item.visitDate||''}} · {{item.doctorName||'门诊医生'}}</text><view class="bill-foot"><text>¥{{Number(item.status===1?item.paidAmount:item.pendingAmount).toFixed(2)}}</text><button v-if="item.status===0" size="mini" @tap="pay(item)">立即支付</button><text v-else>查看详情 ›</text></view></view><view v-if="!loading&&!bills.length" class="bill card">暂无相关账单</view></view></template>
<style scoped lang="scss">.balance{padding:34rpx;border-radius:30rpx;display:flex;flex-direction:column;background:linear-gradient(120deg,#3178ef,#63adff);color:#fff;box-shadow:0 15rpx 32rpx rgba(40,120,255,.23)}.balance text:first-child{font-size:22rpx;opacity:.85}.balance text:nth-child(2){margin:12rpx 0;font-size:51rpx;font-weight:700}.balance text:last-child{font-size:20rpx;opacity:.8}.tabs{margin-top:22rpx;display:flex}.tabs text{flex:1;padding:25rpx;text-align:center;color:#718099}.tabs .active{color:#2878ff;border-bottom:5rpx solid #2878ff}.bill{margin-top:18rpx;padding:25rpx}.bill-head,.bill-foot{display:flex;align-items:center;justify-content:space-between}.bill-head text:first-child{font-size:27rpx;font-weight:700}.bill-head text:last-child{padding:5rpx 12rpx;border-radius:14rpx;background:#fff1de;color:#ef8b12;font-size:19rpx}.bill-head .paid{background:#e6f8f1!important;color:#13a47d!important}.bill-desc{display:block;margin:17rpx 0;color:#7c899e;font-size:22rpx}.bill-foot{padding-top:17rpx;border-top:1rpx solid #edf0f5}.bill-foot>text:first-child{color:#ff7925;font-size:29rpx;font-weight:700}.bill-foot button{margin:0;background:#2878ff;color:#fff}.bill-foot>text:last-child{color:#2878ff;font-size:21rpx}</style>
